import json
import csv
from pathlib import Path
from typing import List, Dict, Any
from contextlib import contextmanager

@contextmanager
def safe_open(filepath: str, mode: str = 'r'):
    file = None
    try:
        file = open(filepath, mode, encoding='utf-8')
        yield file
    except Exception as e:
        raise e
    finally:
        if file:
            file.close()

class FileHandler:
    def __init__(self, base_dir: str = "."):
        self.base_dir = Path(base_dir)
        self.base_dir.mkdir(parents=True, exist_ok=True)

    def read_text(self, filename: str) -> str:
        filepath = self.base_dir / filename
        with open(filepath, 'r', encoding='utf-8') as f:
            return f.read()

    def write_text(self, filename: str, content: str) -> None:
        filepath = self.base_dir / filename
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(content)

    def read_json(self, filename: str) -> Any:
        filepath = self.base_dir / filename
        with open(filepath, 'r', encoding='utf-8') as f:
            return json.load(f)

    def write_json(self, filename: str, data: Any) -> None:
        filepath = self.base_dir / filename
        with open(filepath, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, ensure_ascii=False)

    def read_csv(self, filename: str) -> List[Dict]:
        filepath = self.base_dir / filename
        with open(filepath, 'r', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            return list(reader)

    def write_csv(self, filename: str, data: List[Dict]) -> None:
        if not data:
            return
        filepath = self.base_dir / filename
        with open(filepath, 'w', encoding='utf-8', newline='') as f:
            writer = csv.DictWriter(f, fieldnames=data[0].keys())
            writer.writeheader()
            writer.writerows(data)

handler = FileHandler("data")
handler.write_json("config.json", {"key": "value"})
