from functools import wraps
import time
from typing import Callable, Any, TypeVar
import logging

T = TypeVar('T')

def timer(func: Callable[..., T]) -> Callable[..., T]:
    @wraps(func)
    def wrapper(*args, **kwargs) -> T:
        start = time.perf_counter()
        result = func(*args, **kwargs)
        end = time.perf_counter()
        print(f"{func.__name__} took {end - start:.4f} seconds")
        return result
    return wrapper

def retry(times: int, delay: float = 1.0):
    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @wraps(func)
        def wrapper(*args, **kwargs) -> T:
            for attempt in range(times):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == times - 1:
                        raise
                    time.sleep(delay)
            return None
        return wrapper
    return decorator

def validate_input(*types):
    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @wraps(func)
        def wrapper(*args, **kwargs) -> T:
            for i, (arg, typ) in enumerate(zip(args, types)):
                if not isinstance(arg, typ):
                    raise TypeError(f"Argument {i} must be {typ}")
            return func(*args, **kwargs)
        return wrapper
    return decorator

def cache_result(func: Callable[..., T]) -> Callable[..., T]:
    cache = {}

    @wraps(func)
    def wrapper(*args) -> T:
        key = str(args)
        if key not in cache:
            cache[key] = func(*args)
        return cache[key]
    return wrapper

@timer
@retry(times=3, delay=0.5)
def fetch_data(url: str) -> dict:
    return {"status": "ok"}

@validate_input(str, int)
def greet(name: str, age: int) -> str:
    return f"{name} is {age} years old"
