import pandas as pd
import numpy as np
from typing import List, Dict, Optional

class DataProcessor:
    def __init__(self, data: pd.DataFrame):
        self.df = data.copy()

    def clean(self) -> 'DataProcessor':
        self.df = self.df.dropna()
        self.df = self.df.drop_duplicates()
        return self

    def fill_missing(self, column: str, value: Any) -> 'DataProcessor':
        self.df[column] = self.df[column].fillna(value)
        return self

    def filter_by(self, column: str, value: Any) -> 'DataProcessor':
        self.df = self.df[self.df[column] == value]
        return self

    def group_and_aggregate(
        self, 
        group_by: List[str], 
        agg_dict: Dict[str, List[str]]
    ) -> pd.DataFrame:
        return self.df.groupby(group_by).agg(agg_dict)

    def add_column(self, name: str, values: pd.Series) -> 'DataProcessor':
        self.df[name] = values
        return self

    def get_stats(self) -> pd.DataFrame:
        return self.df.describe()

    def to_csv(self, filepath: str) -> None:
        self.df.to_csv(filepath, index=False)

    @staticmethod
    def from_csv(filepath: str) -> 'DataProcessor':
        df = pd.read_csv(filepath)
        return DataProcessor(df)

data = {
    'name': ['Alice', 'Bob', 'Charlie', 'Alice'],
    'age': [25, 30, 35, 25],
    'salary': [50000, 60000, 70000, 50000]
}
processor = DataProcessor(pd.DataFrame(data))
processor.clean().filter_by('age', 25)
