import numpy as np
from sklearn.model_selection import train_test_split, cross_val_score
from sklearn.preprocessing import StandardScaler, LabelEncoder
from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score, classification_report
import joblib
from typing import Tuple, Optional

class MLModel:
    def __init__(self, model_type: str = 'random_forest'):
        self.model = RandomForestClassifier(n_estimators=100, random_state=42)
        self.scaler = StandardScaler()
        self.label_encoder = LabelEncoder()
        self.is_fitted = False

    def preprocess(
        self, 
        X: np.ndarray, 
        y: Optional[np.ndarray] = None,
        fit: bool = True
    ) -> Tuple[np.ndarray, Optional[np.ndarray]]:
        if fit:
            X_scaled = self.scaler.fit_transform(X)
            if y is not None:
                y_encoded = self.label_encoder.fit_transform(y)
                return X_scaled, y_encoded
        else:
            X_scaled = self.scaler.transform(X)
            if y is not None:
                y_encoded = self.label_encoder.transform(y)
                return X_scaled, y_encoded
        return X_scaled, None

    def train(
        self, 
        X: np.ndarray, 
        y: np.ndarray,
        test_size: float = 0.2
    ) -> dict:
        X_processed, y_processed = self.preprocess(X, y, fit=True)
        X_train, X_test, y_train, y_test = train_test_split(
            X_processed, y_processed, test_size=test_size, random_state=42
        )
        self.model.fit(X_train, y_train)
        self.is_fitted = True
        y_pred = self.model.predict(X_test)
        return {
            'accuracy': accuracy_score(y_test, y_pred),
            'classification_report': classification_report(y_test, y_pred)
        }

    def predict(self, X: np.ndarray) -> np.ndarray:
        if not self.is_fitted:
            raise ValueError("Model must be trained before prediction")
        X_scaled, _ = self.preprocess(X, fit=False)
        predictions = self.model.predict(X_scaled)
        return self.label_encoder.inverse_transform(predictions)

    def cross_validate(self, X: np.ndarray, y: np.ndarray, cv: int = 5) -> float:
        X_processed, y_processed = self.preprocess(X, y, fit=True)
        scores = cross_val_score(self.model, X_processed, y_processed, cv=cv)
        return scores.mean()

    def save(self, filepath: str) -> None:
        joblib.dump({
            'model': self.model,
            'scaler': self.scaler,
            'label_encoder': self.label_encoder
        }, filepath)

    @classmethod
    def load(cls, filepath: str) -> 'MLModel':
        data = joblib.load(filepath)
        instance = cls()
        instance.model = data['model']
        instance.scaler = data['scaler']
        instance.label_encoder = data['label_encoder']
        instance.is_fitted = True
        return instance
